import { createClient } from '@supabase/supabase-js';
import { Asset, Department, Employee, EquipmentRequest, AuditSession, UserAccount, AppNotification } from '../types';

const SUPABASE_URL = 'https://zcbphldaobriwkpqcupa.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_5GUfPGtwRSMJHjNqocwqwA_GUm6U0PE';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const localDB = {
  save: (key: string, data: any) => localStorage.setItem(`assettrack_${key}`, JSON.stringify(data)),
  get: (key: string) => {
    const val = localStorage.getItem(`assettrack_${key}`);
    return val ? JSON.parse(val) : null;
  }
};

const DATA_MARKER = '--- [SISTEMA-DATA-V1] ---';

const toB64 = (str: string) => {
  try {
    return btoa(unescape(encodeURIComponent(str)));
  } catch (e) {
    console.error("Erro na codificação Base64:", e);
    return "";
  }
};

const fromB64 = (str: string) => {
  try {
    return decodeURIComponent(escape(atob(str)));
  } catch (e) {
    console.error("Erro na decodificação Base64:", e);
    return "";
  }
};

const deflateAsset = (asset: Asset) => {
  const { 
    serialNumber, ram, storage, processor, screenSize, 
    caseModel, isWireless, monitorInputs, isAbnt, hasNumericKeypad, 
    ...dbReady 
  } = asset;

  const virtualFields = {
    serialNumber, ram, storage, processor, screenSize, 
    caseModel, isWireless, monitorInputs, isAbnt, hasNumericKeypad
  };

  const cleanObs = (dbReady.observations || '').split(DATA_MARKER)[0].trim();
  const encodedData = toB64(JSON.stringify(virtualFields));
  dbReady.observations = `${cleanObs}\n\n${DATA_MARKER}\n${encodedData}`;

  return dbReady;
};

const inflateAsset = (dbAsset: any): Asset => {
  if (!dbAsset || typeof dbAsset.observations !== 'string' || !dbAsset.observations.includes(DATA_MARKER)) {
    return { ...dbAsset, history: dbAsset.history || [] } as Asset;
  }
  try {
    const parts = dbAsset.observations.split(DATA_MARKER);
    const cleanObs = parts[0].trim();
    const encodedData = parts[1].trim();
    const decodedStr = fromB64(encodedData);
    if (!decodedStr) return { ...dbAsset, history: dbAsset.history || [] } as Asset;
    const virtualFields = JSON.parse(decodedStr);
    return { ...dbAsset, ...virtualFields, observations: cleanObs, history: dbAsset.history || [] } as Asset;
  } catch (e) {
    return { ...dbAsset, history: dbAsset.history || [] } as Asset;
  }
};

const deflateUser = (user: UserAccount) => {
  const { employeeId, password, modules, ...rest } = user;
  const dbReady: any = {
    id: rest.id,
    name: rest.name,
    username: (rest.username || '').toLowerCase().trim(),
    sector: (rest.sector || '').split(DATA_MARKER)[0].trim(),
    password: password || 'admin123'
  };
  const virtualFields = { employeeId, password: dbReady.password, modules };
  const encodedData = toB64(JSON.stringify(virtualFields));
  dbReady.sector = `${dbReady.sector} ${DATA_MARKER}${encodedData}`;
  return dbReady;
};

const inflateUser = (dbUser: any): UserAccount => {
  if (!dbUser) return null as any;
  if (typeof dbUser.sector !== 'string' || !dbUser.sector.includes(DATA_MARKER)) {
    return {
      modules: [],
      ...dbUser
    } as UserAccount;
  }
  try {
    const parts = dbUser.sector.split(DATA_MARKER);
    const cleanSector = parts[0].trim();
    const encodedData = parts[1].trim();
    const decodedStr = fromB64(encodedData);
    if (!decodedStr) return { modules: [], ...dbUser } as UserAccount;
    const virtualFields = JSON.parse(decodedStr);
    return { ...dbUser, ...virtualFields, sector: cleanSector, password: virtualFields.password || dbUser.password } as UserAccount;
  } catch (e) {
    return { modules: [], ...dbUser } as UserAccount;
  }
};

