import { EquipmentRequest, Employee, Asset, AssetType, UserAccount, AssetTypeConfig } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  currentUser: UserAccount;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
  onRemoveRequest?: (id: string) => Promise<void>;
  // Fix: Add missing assetTypeConfigs property to interface
  assetTypeConfigs: AssetTypeConfig[];
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ 
  requests, 
  employees, 
  assets, 
  currentUser, 
  onAddRequest, 
  onUpdateStatus, 
  onUpdateRequest, 
  onRemoveRequest,
  // Fix: Destructure assetTypeConfigs
  assetTypeConfigs 
}) => {
  const [showModal, setShowModal] = useState(false);
  const [showTermModal, setShowTermModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: currentUser.id, 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployee = (id: string) => employees.find(e => e.id === id);
  const getEmployeeName = (id: string) => getEmployee(id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => getEmployee(id)?.sector || 'Setor não informado';

  const getLinkedAssetInfo = (assetId?: string) => {
    if (!assetId) return null;
    return assets.find(a => a.id === assetId);
  };

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0 || !newReq.employeeId) {
      alert("Preencha todos os campos.");
      return;
    }
    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({ type, isPurchaseOrder: false }))
      });
      setShowModal(false);
      setNewReq({ requesterId: currentUser.id, employeeId: '', items: [], observation: '' });
    } catch (err) { alert("Erro ao criar requisição."); }
    finally { setIsSubmitting(false); }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = { type: selectedRequest.items[index], linkedAssetId: assetId, isPurchaseOrder: false };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = { type: selectedRequest.items[index], linkedAssetId: undefined, isPurchaseOrder: true, purchaseStatus: 'Pendente' };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const handleRemove = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!onRemoveRequest) return;
    if (confirm("Tem certeza que deseja excluir permanentemente esta requisição?")) {
      try {
        await onRemoveRequest(id);
        if (selectedRequest?.id === id) setSelectedRequest(null);
      } catch (err) { alert("Falha ao excluir requisição."); }
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4 print:hidden">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
                req.status === 'Aprovado' ? 'bg-blue-100 text-blue-700' :
                req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-700' :
                req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'
              }`}>
                {req.status === 'Preparando' ? <Wrench className="w-6 h-6" /> : req.status === 'Entregue' ? <ShieldCheck className="w-6 h-6" /> : <FileText className="w-6 h-6" />}
              </div>
              <div>
                <p className="font-black text-slate-900">{req.id}</p>
                <p className="text-sm text-slate-600 font-semibold">Para: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>

            <div className="flex items-center gap-4">
               <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tight ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-800 border-amber-200' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-800 border-blue-200' :
                 req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-800 border-indigo-200' :
                 req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-800 border-emerald-200' : 'bg-rose-100 text-rose-800 border-rose-200'
               }`}>
                 {req.status}
               </span>
               <button onClick={(e) => handleRemove(e, req.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100">
                 <Trash2 className="w-5 h-5" />
               </button>
               <ChevronRight className="w-5 h-5 text-slate-400 group-hover:text-blue-600 transition-transform group-hover:translate-x-1" />
            </div>
          </div>
        ))}

        {requests.length === 0 && (
          <div className="bg-white p-16 rounded-[2.5rem] border border-dashed border-slate-300 text-center space-y-4">
             <p className="text-slate-600 font-black uppercase tracking-widest text-xs">Nenhuma solicitação encontrada.</p>
          </div>
        )}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl h-fit space-y-6 sticky top-24 print:hidden">
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-slate-900 hover:bg-black text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 uppercase tracking-widest text-xs"
        >
          <Plus className="w-5 h-5" />
          <span>Nova Requisição</span>
        </button>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between">
                 <h3 className="text-xl font-black uppercase tracking-tight">Nova Requisição</h3>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto flex-1">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</label>
                    <select className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold" value={newReq.employeeId} onChange={e => setNewReq({...newReq, employeeId: e.target.value})} required>
                       <option value="">Selecione...</option>
                       {employees.map(emp => <option key={emp.id} value={emp.id}>{emp.name}</option>)}
                    </select>
                 </div>
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Itens</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                       {/* Fix: Use assetTypeConfigs names if available, falling back to ASSET_TYPES */}
                       {(assetTypeConfigs.length > 0 ? assetTypeConfigs.map(t => t.name) : ASSET_TYPES).map(type => (
                         <button key={type} type="button" onClick={() => toggleItem(type as AssetType)} className={`p-3 rounded-xl border text-[10px] font-black uppercase ${newReq.items.includes(type as AssetType) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'}`}>
                           {type}
                         </button>
                       ))}
                    </div>
                 </div>
                 <button type="submit" disabled={isSubmitting} className="w-full bg-blue-600 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs disabled:bg-slate-300">
                    {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "Abrir Requisição"}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col border-l border-slate-200">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-black text-slate-900">{selectedRequest.id}</h3>
                <p className="text-sm text-slate-600 font-bold">Destino: {getEmployeeName(selectedRequest.employeeId)}</p>
              </div>
              <div className="flex items-center gap-2">
                 <button onClick={(e) => handleRemove(e, selectedRequest.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors" title="Excluir Requisição">
                   <Trash2 className="w-5 h-5" />
                 </button>
                 <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-500"><X className="w-6 h-6" /></button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-6">
               {selectedRequest.items.map((itemType, idx) => {
                  const fulfillment = selectedRequest.itemFulfillments?.[idx];
                  const isLinked = !!fulfillment?.linkedAssetId;
                  return (
                    <div key={idx} className={`p-5 rounded-3xl border ${isLinked ? 'bg-emerald-50 border-emerald-200' : 'bg-white border-slate-200'}`}>
                      <div className="flex items-center justify-between mb-4">
                        <span className="font-black text-slate-900">{itemType}</span>
                        {isLinked && <span className="text-[10px] font-black uppercase text-emerald-800">Vinculado: {fulfillment.linkedAssetId}</span>}
                      </div>
                      {!isLinked && (
                        <button onClick={() => setItemToLink({ index: idx, type: itemType })} className="w-full py-2 bg-slate-100 rounded-xl text-[10px] font-black uppercase hover:bg-blue-600 hover:text-white transition-all">
                          Vincular Ativo
                        </button>
                      )}
                      {itemToLink?.index === idx && (
                        <div className="mt-4 p-4 bg-slate-100 rounded-2xl border border-slate-300">
                           <div className="space-y-2">
                              {availableAssetsByType(itemType).map(asset => (
                                <button key={asset.id} onClick={() => handleLinkAsset(idx, asset.id)} className="w-full text-left p-3 bg-white border border-slate-300 rounded-xl hover:border-blue-600">
                                   <p className="text-xs font-black">{asset.id} - {asset.brand} {asset.model}</p>
                                </button>
                              ))}
                           </div>
                        </div>
                      )}
                    </div>
                  );
               })}
            </div>

            <div className="p-8 border-t border-slate-200 flex flex-col gap-2">
               {selectedRequest.status === 'Pendente' && <button onClick={() => handleStatusChange('Aprovado')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs">Aprovar Pedido</button>}
               {selectedRequest.status === 'Aprovado' && <button onClick={() => handleStatusChange('Preparando')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Iniciar Preparação</button>}
               {selectedRequest.status === 'Preparando' && <button onClick={() => handleStatusChange('Entregue')} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs">Confirmar Entrega</button>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RequestsManager;

import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  Search, 
  Check, 
  AlertCircle,
  CreditCard,
  FileText,
  Package,
  Truck,
  X,
  Link as LinkIcon,
  CheckSquare,
  Square,
  MoreHorizontal,
  ChevronRight,
  ShieldCheck,
  Zap,
  Tag,
  QrCode,
  DollarSign,
  Plus,
  ArrowRight,
  ExternalLink,
  Loader2,
  Clock
} from 'lucide-react';
// Fix: Import AssetTypeConfig from types
import { EquipmentRequest, Employee, ItemFulfillment, Quotation, Asset, HistoryEntry, AssetType, AssetTypeConfig } from '../types';
import { ASSET_TYPES } from '../constants';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
  onAssetCreated: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string; history?: HistoryEntry[] }) => Promise<void>;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  // Fix: Add missing assetTypeConfigs property to interface
  assetTypeConfigs: AssetTypeConfig[];
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ 
  requests, 
  employees, 
  onUpdateRequest, 
  onAssetCreated, 
  onAddRequest,
  // Fix: Destructure assetTypeConfigs
  assetTypeConfigs 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Todos');
  const [activeSelection, setActiveSelection] = useState<{ requestId: string; fIndex: number } | null>(null);
  const [showDirectOrderModal, setShowDirectOrderModal] = useState(false);
  const [showReceiptForm, setShowReceiptForm] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newDirectOrder, setNewDirectOrder] = useState({
    type: 'Notebook' as AssetType,
    observation: ''
  });

  const [receiptData, setReceiptData] = useState<Partial<Asset>>({
    brand: '',
    model: '',
    id: '',
    observations: ''
  });

  const currentRequest = useMemo(() => {
    if (!activeSelection) return null;
    return requests.find(r => r.id === activeSelection.requestId) || null;
  }, [requests, activeSelection]);

  const currentFulfillment = useMemo(() => {
    if (!currentRequest || activeSelection === null) return null;
    return currentRequest.itemFulfillments?.[activeSelection.fIndex] || null;
  }, [currentRequest, activeSelection]);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (employee?.name || 'Estoque').toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());
    const status = item.fulfillment.purchaseStatus || 'Pendente';
    const matchesStatus = statusFilter === 'Todos' || status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'Estoque TI (Reposição)';

  const handleUpdateQuotation = async (qIndex: number, field: keyof Quotation, value: any) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    const item = { ...newFulfillments[activeSelection.fIndex] };
    const quotations = [...(item.quotations || [
      { url: '', price: 0, deliveryPrediction: '' }, 
      { url: '', price: 0, deliveryPrediction: '' }, 
      { url: '', price: 0, deliveryPrediction: '' }
    ])];
    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    item.quotations = quotations;
    newFulfillments[activeSelection.fIndex] = item;
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = async (qIndex: number) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Cotação Aprovada', 
      approvedQuotationIndex: qIndex 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleAuthorizeOrder = async () => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Pedido Autorizado' 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleSetComprado = async (requestId: string, fIndex: number) => {
    const req = requests.find(r => r.id === requestId);
    if (!req) return;
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIndex] = { ...newFulfillments[fIndex], purchaseStatus: 'Comprado' };
    await onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleOpenReceipt = () => {
    if (!currentFulfillment) return;
    setReceiptData({
      brand: '',
      model: '',
      id: '', // Deixamos em branco para permitir geração automática se o usuário não preencher
      observations: `Item recebido via Pedido de Compra referente à requisição ${currentRequest?.id}`,
      type: currentFulfillment.type
    });
    setShowReceiptForm(true);
  };

  const handleFinalizeAndCreateAsset = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentRequest || activeSelection === null || !currentFulfillment) return;
    setIsSubmitting(true);

    try {
      // O App.tsx tratará a geração do ID se receiptData.id estiver vazio
      await onAssetCreated({
        id: receiptData.id || undefined,
        brand: receiptData.brand || '',
        model: receiptData.model || '',
        type: currentFulfillment.type,
        departmentId: 'DEPT-1',
        status: currentRequest.employeeId ? 'Em Uso' : 'Disponível',
        assignedTo: currentRequest.employeeId || undefined,
        observations: receiptData.observations || '',
        photos: [],
        history: [
          {
            id: Math.random().toString(),
            date: new Date().toISOString(),
            type: 'Criação',
            description: `Tombamento via compra ref. ${currentRequest.id}`,
            performedBy: 'Sistema Financeiro'
          }
        ]
      });

      const newFulfillments = [...(currentRequest.itemFulfillments || [])];
      // Nota: o ID real será gerado pelo App.tsx/Banco, aqui usamos o fornecido ou o placeholder
      newFulfillments[activeSelection.fIndex] = { 
        ...newFulfillments[activeSelection.fIndex], 
        isDelivered: true, 
        linkedAssetId: receiptData.id || 'AUTO-GERADO'
      };

      await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });

      setShowReceiptForm(false);
      setActiveSelection(null);
    } catch (err) {
      alert("Erro ao finalizar tombamento.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCreateDirectOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await onAddRequest({
        requesterId: '1',
        employeeId: '', 
        items: [newDirectOrder.type],
        observation: newDirectOrder.observation,
        itemFulfillments: [{
          type: newDirectOrder.type,
          isPurchaseOrder: true,
          purchaseStatus: 'Pendente',
          quotations: [
            { url: '', price: 0, deliveryPrediction: '' },
            { url: '', price: 0, deliveryPrediction: '' },
            { url: '', price: 0, deliveryPrediction: '' }
          ]
        }]
      });
      setShowDirectOrderModal(false);
      setNewDirectOrder({ type: 'Notebook', observation: '' });
    } catch (err) {
      alert("Erro ao criar pedido.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 flex-1 w-full">
          {[
            { label: 'Cotações', count: purchaseItems.filter(i => (i.fulfillment.purchaseStatus || 'Pendente') === 'Pendente').length, color: 'text-amber-600', bg: 'bg-amber-50' },
            { label: 'Autorização', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Cotação Aprovada').length, color: 'text-blue-600', bg: 'bg-blue-50' },
            { label: 'Autorizados', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pedido Autorizado').length, color: 'text-indigo-600', bg: 'bg-indigo-50' },
            { label: 'Em Trânsito', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length, color: 'text-emerald-600', bg: 'bg-emerald-50' },
          ].map((stat, i) => (
            <div key={i} className={`${stat.bg} p-5 rounded-[1.5rem] border border-slate-100 shadow-sm`}>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{stat.label}</p>
              <p className={`text-2xl font-black ${stat.color} tracking-tight`}>{stat.count}</p>
            </div>
          ))}
        </div>
        <button 
          onClick={() => setShowDirectOrderModal(true)}
          className="w-full lg:w-auto bg-slate-900 hover:bg-black text-white px-8 py-5 rounded-2xl font-black shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-[10px] transition-all"
        >
          <Plus className="w-5 h-5" /> Nova Ordem de Compra
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Protocolo</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipamento</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Destinatário</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Workflow</th>
                <th className="px-6 py-5 text-right"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item) => (
                <tr 
                  key={`${item.request.id}-${item.index}`} 
                  className="hover:bg-slate-50/50 transition-colors group cursor-pointer" 
                  onClick={() => setActiveSelection({ requestId: item.request.id, fIndex: item.index })}
                >
                  <td className="px-6 py-6 font-mono text-xs font-bold text-slate-400">{item.request.id}</td>
                  <td className="px-6 py-6 font-bold text-slate-800">{item.fulfillment.type}</td>
                  <td className="px-6 py-6">
                    <span className="text-sm font-bold text-slate-700">{getEmployeeName(item.request.employeeId)}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                      (item.fulfillment.purchaseStatus || 'Pendente') === 'Pendente' ? 'bg-amber-50 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Cotação Aprovada' ? 'bg-blue-50 text-blue-600 border-blue-200' :
                      item.fulfillment.purchaseStatus === 'Pedido Autorizado' ? 'bg-indigo-50 text-indigo-600 border-indigo-200' : 'bg-emerald-50 text-emerald-600 border-emerald-200'
                    }`}>
                      {item.fulfillment.purchaseStatus || 'Pendente'}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    <div className="flex items-center justify-end gap-2 text-blue-600 opacity-0 group-hover:opacity-100 transition-all font-black text-[10px] uppercase">
                      Gerenciar <ChevronRight className="w-4 h-4" />
                    </div>
                  </td>
                </tr>
              ))}
              {filteredItems.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs opacity-50">
                    Nenhum pedido de compra ativo.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {activeSelection && currentRequest && currentFulfillment && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setActiveSelection(null)} />
          <div className="relative w-full max-w-2xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                    <ShoppingCart className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black uppercase tracking-tight">Gestão de Ordem de Compra</h3>
                    <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">{currentRequest.id} • Item #{activeSelection.fIndex + 1}</p>
                  </div>
                </div>
                <button onClick={() => setActiveSelection(null)} className="p-3 hover:bg-slate-200 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
              <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-2 tracking-widest">Item Solicitado</p>
                <div className="flex items-center gap-4">
                   <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center border border-slate-200 shadow-sm">
                      <Package className="w-7 h-7 text-blue-600" />
                   </div>
                   <div>
                      <h4 className="text-lg font-black text-slate-900">{currentFulfillment.type}</h4>
                      <p className="text-xs font-bold text-slate-600">Para: {getEmployeeName(currentRequest.employeeId)}</p>
                   </div>
                </div>
              </div>

              {/* ETAPA 1: COTAÇÕES */}
              {(currentFulfillment.purchaseStatus || 'Pendente') === 'Pendente' && (
                <div className="space-y-6">
                  <div className="flex items-center gap-2">
                    <DollarSign className="w-5 h-5 text-amber-600" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Mapa Comparativo de Cotações</h4>
                  </div>
                  <div className="space-y-4">
                    {[0, 1, 2].map(qIdx => (
                      <div key={qIdx} className="bg-white border-2 border-slate-200 rounded-3xl p-6 hover:border-blue-400 transition-all shadow-sm">
                        <div className="flex items-center justify-between mb-4">
                           <span className="text-[10px] font-black uppercase bg-slate-100 px-3 py-1 rounded-full text-slate-600">Fornecedor {qIdx + 1}</span>
                           <button 
                            onClick={() => handleApproveQuotation(qIdx)}
                            className="bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-100 hover:bg-emerald-600 hover:text-white transition-all"
                           >
                              Escolher Fornecedor
                           </button>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                           <div className="relative">
                              <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                              <input 
                                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500" 
                                placeholder="Link do produto (URL)" 
                                value={currentFulfillment.quotations?.[qIdx]?.url || ''}
                                onChange={e => handleUpdateQuotation(qIdx, 'url', e.target.value)}
                              />
                           </div>
                           <div className="relative">
                              <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                              <input 
                                type="number"
                                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500" 
                                placeholder="Preço (R$)" 
                                value={currentFulfillment.quotations?.[qIdx]?.price || ''}
                                onChange={e => handleUpdateQuotation(qIdx, 'price', parseFloat(e.target.value))}
                              />
                           </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* ETAPA 2: AUTORIZAÇÃO */}
              {currentFulfillment.purchaseStatus === 'Cotação Aprovada' && (
                <div className="space-y-6 animate-in slide-in-from-bottom-4">
                  <div className="flex items-center gap-2">
                    <ShieldCheck className="w-5 h-5 text-blue-600" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Aprovação da Diretoria</h4>
                  </div>
                  <div className="bg-blue-600 rounded-[2.5rem] p-8 text-white shadow-xl">
                     <p className="text-[10px] font-black uppercase opacity-70 mb-4 tracking-widest">Fornecedor Selecionado</p>
                     <div className="flex items-center justify-between mb-8">
                        <div>
                          <p className="text-3xl font-black">R$ {currentFulfillment.quotations?.[currentFulfillment.approvedQuotationIndex || 0].price?.toLocaleString('pt-BR')}</p>
                          <p className="text-xs font-bold text-blue-100 mt-1">
                             Aguardando sua autorização para prosseguir com a compra.
                          </p>
                        </div>
                        <a 
                          href={currentFulfillment.quotations?.[currentFulfillment.approvedQuotationIndex || 0].url} 
                          target="_blank" 
                          className="bg-white/20 hover:bg-white/40 p-4 rounded-2xl transition-all"
                        >
                          <ExternalLink className="w-6 h-6" />
                        </a>
                     </div>
                     <button 
                      onClick={handleAuthorizeOrder}
                      className="w-full bg-white text-blue-600 font-black py-5 rounded-[2rem] uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all"
                     >
                       <CheckSquare className="w-5 h-5" /> Autorizar Pedido
                     </button>
                  </div>
                </div>
              )}

              {/* ETAPA 3: PAGAMENTO */}
              {currentFulfillment.purchaseStatus === 'Pedido Autorizado' && (
                <div className="space-y-6">
                  <div className="flex items-center gap-2">
                    <CreditCard className="w-5 h-5 text-indigo-600" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Financeiro</h4>
                  </div>
                  <div className="bg-indigo-600 rounded-[2.5rem] p-10 text-white shadow-xl text-center">
                     <p className="text-sm font-bold mb-8">O pedido foi autorizado. Realize o pagamento e confirme o envio abaixo.</p>
                     <button 
                      onClick={() => handleSetComprado(currentRequest.id, activeSelection.fIndex)}
                      className="w-full bg-white text-indigo-600 font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs flex items-center justify-center gap-3"
                     >
                        <Truck className="w-6 h-6" /> Confirmar Pagamento e Envio
                     </button>
                  </div>
                </div>
              )}

              {/* ETAPA 4: RECEBIMENTO */}
              {currentFulfillment.purchaseStatus === 'Comprado' && (
                <div className="space-y-6">
                   <div className="flex items-center gap-2 text-emerald-600">
                    <Truck className="w-6 h-6" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Equipamento em Trânsito</h4>
                  </div>
                  <div className="bg-emerald-600 rounded-[2.5rem] p-10 text-white shadow-xl text-center">
                     <Package className="w-16 h-16 mx-auto mb-6 animate-bounce" />
                     <p className="font-bold mb-8">O item está a caminho. Clique abaixo ao recebê-lo fisicamente.</p>
                     <button 
                      onClick={handleOpenReceipt}
                      className="w-full bg-white text-emerald-600 font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs"
                     >
                        Registrar Recebimento
                     </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* MODAL: NOVA ORDEM DIRETA */}
      {showDirectOrderModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between">
                 <div className="flex items-center gap-3">
                    <ShoppingCart className="w-5 h-5" />
                    <h3 className="text-xl font-black uppercase tracking-tight">Nova Ordem de Compra</h3>
                 </div>
                 <button onClick={() => setShowDirectOrderModal(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleCreateDirectOrder} className="p-10 space-y-6">
                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Equipamento</label>
                    <select 
                      className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none"
                      value={newDirectOrder.type}
                      onChange={e => setNewDirectOrder({...newDirectOrder, type: e.target.value as AssetType})}
                    >
                      {/* Fix: Use assetTypeConfigs names if available, falling back to ASSET_TYPES */}
                      {(assetTypeConfigs.length > 0 ? assetTypeConfigs.map(t => t.name) : ASSET_TYPES).map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                 </div>
                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold h-32 outline-none"
                      placeholder="Motivo da compra..."
                      value={newDirectOrder.observation}
                      onChange={e => setNewDirectOrder({...newDirectOrder, observation: e.target.value})}
                      required
                    />
                 </div>
                 <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs disabled:bg-slate-300"
                 >
                    {isSubmitting ? 'Processando...' : 'Abrir Ordem de Compra'}
                 </button>
              </form>
           </div>
        </div>
      )}

      {/* MODAL: TOMBAMENTO */}
      {showReceiptForm && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
           <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden">
              <div className="bg-emerald-600 p-8 text-white flex items-center justify-between">
                 <h3 className="text-xl font-black uppercase tracking-tight">Tombamento</h3>
                 <button onClick={() => setShowReceiptForm(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleFinalizeAndCreateAsset} className="p-10 space-y-6">
                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">ID Patrimonial (Vazio = Auto)</label>
                    <input 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-mono font-black text-lg text-center" 
                      value={receiptData.id} 
                      onChange={e => setReceiptData({...receiptData, id: e.target.value})} 
                      placeholder="Ex: AST-5050"
                    />
                 </div>
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400">Marca</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-200" placeholder="Dell" value={receiptData.brand} onChange={e => setReceiptData({...receiptData, brand: e.target.value})} required />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400">Modelo</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-200" placeholder="G15" value={receiptData.model} onChange={e => setReceiptData({...receiptData, model: e.target.value})} required />
                    </div>
                 </div>
                 <button type="submit" disabled={isSubmitting} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs">
                    {isSubmitting ? 'Salvando...' : 'Concluir e Registrar Ativo'}
                 </button>
              </form>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default PurchaseOrderManager;

import React, { useState } from 'react';
import { 
  Calculator, 
  Book, 
  Layers, 
  Plus, 
  Search, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  ArrowRight,
  ShieldCheck,
  Briefcase,
  Tag,
  DollarSign,
  Loader2
} from 'lucide-react';
import { AccountingAccount, AccountingClassification, AssetTypeConfig } from '../types';

interface AccountingManagerProps {
  accounts: AccountingAccount[];
  classifications: AccountingClassification[];
  assetTypes: AssetTypeConfig[];
  onAddAccount: (acc: Omit<AccountingAccount, 'id'>) => Promise<void>;
  onUpdateAccount: (acc: AccountingAccount) => Promise<void>;
  onRemoveAccount: (id: string) => Promise<void>;
  onAddClassification: (cls: Omit<AccountingClassification, 'id'>) => Promise<void>;
  onUpdateClassification: (cls: AccountingClassification) => Promise<void>;
  onRemoveClassification: (id: string) => Promise<void>;
  onAddAssetType: (type: Omit<AssetTypeConfig, 'id'>) => Promise<void>;
  onUpdateAssetType: (type: AssetTypeConfig) => Promise<void>;
  onRemoveAssetType: (id: string) => Promise<void>;
}

const AccountingManager: React.FC<AccountingManagerProps> = ({
  accounts, classifications, assetTypes,
  onAddAccount, onUpdateAccount, onRemoveAccount,
  onAddClassification, onUpdateClassification, onRemoveClassification,
  onAddAssetType, onUpdateAssetType, onRemoveAssetType
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'accounts' | 'classifications' | 'asset-types'>('accounts');
  const [showForm, setShowForm] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Form states
  const [formData, setFormData] = useState<any>({});

  const handleTabChange = (tab: 'accounts' | 'classifications' | 'asset-types') => {
    setActiveSubTab(tab);
    setShowForm(false);
    setEditingItem(null);
    setFormData({});
  };

  const handleOpenForm = (item: any = null) => {
    setEditingItem(item);
    if (activeSubTab === 'accounts') {
      setFormData(item || { code: '', name: '' });
    } else if (activeSubTab === 'classifications') {
      setFormData(item || { name: '', code: '', accountId: '' });
    } else {
      setFormData(item || { name: '', classificationId: '' });
    }
    setShowForm(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (activeSubTab === 'accounts') {
        if (editingItem) await onUpdateAccount(formData);
        else await onAddAccount(formData);
      } else if (activeSubTab === 'classifications') {
        if (editingItem) await onUpdateClassification(formData);
        else await onAddClassification(formData);
      } else {
        if (editingItem) await onUpdateAssetType(formData);
        else await onAddAssetType(formData);
      }
      setShowForm(false);
      setEditingItem(null);
    } catch (err: any) {
      console.error("Erro Contabil:", err);
      alert(`Falha ao salvar: ${err.message || 'Erro desconhecido'}\n\nVerifique se as tabelas foram criadas no Supabase.`);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string, type: string) => {
    if (!confirm(`Deseja realmente excluir este registro?`)) return;
    try {
      if (type === 'account') await onRemoveAccount(id);
      else if (type === 'classification') await onRemoveClassification(id);
      else await onRemoveAssetType(id);
    } catch (err: any) {
      alert(`Erro ao excluir: ${err.message}`);
    }
  };

  const getAccountName = (id: string) => accounts.find(a => a.id === id)?.name || 'N/A';
  const getClassificationName = (id: string) => classifications.find(c => c.id === id)?.name || 'N/A';

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="bg-white rounded-[2.5rem] p-2 border border-slate-100 shadow-sm flex gap-2">
        <button 
          onClick={() => handleTabChange('accounts')}
          className={`flex-1 py-4 px-6 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2 ${
            activeSubTab === 'accounts' ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:bg-slate-50'
          }`}
        >
          <DollarSign className="w-4 h-4" /> Contas Contábeis
        </button>
        <button 
          onClick={() => handleTabChange('classifications')}
          className={`flex-1 py-4 px-6 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2 ${
            activeSubTab === 'classifications' ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:bg-slate-50'
          }`}
        >
          <Book className="w-4 h-4" /> Classificações
        </button>
        <button 
          onClick={() => handleTabChange('asset-types')}
          className={`flex-1 py-4 px-6 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2 ${
            activeSubTab === 'asset-types' ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:bg-slate-50'
          }`}
        >
          <Layers className="w-4 h-4" /> Tipos de Ativos
        </button>
      </div>

      <div className="flex justify-between items-center">
        <h3 className="text-2xl font-black text-slate-800 tracking-tight flex items-center gap-3">
          {activeSubTab === 'accounts' && <><DollarSign className="w-7 h-7 text-blue-600" /> Gestão de Contas</>}
          {activeSubTab === 'classifications' && <><Book className="w-7 h-7 text-indigo-600" /> Classificações Contábeis</>}
          {activeSubTab === 'asset-types' && <><Layers className="w-7 h-7 text-emerald-600" /> Cadastro de Tipos</>}
        </h3>
        <button 
          onClick={() => handleOpenForm()}
          className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-blue-100 flex items-center gap-2 transition-all transform active:scale-95 uppercase text-[10px] tracking-widest"
        >
          <Plus className="w-5 h-5" /> Adicionar Novo
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Informação Principal</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Detalhes / Vínculos</th>
              <th className="px-8 py-5 text-right"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {activeSubTab === 'accounts' && accounts.map(acc => (
              <tr key={acc.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-6">
                  <p className="font-black text-slate-900 leading-none mb-1">{acc.name}</p>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{acc.code}</p>
                </td>
                <td className="px-8 py-6">
                  <span className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 px-3 py-1 rounded-full">Conta Ativa</span>
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => handleOpenForm(acc)} className="p-2 text-slate-400 hover:text-blue-600"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => handleDelete(acc.id, 'account')} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
            {activeSubTab === 'classifications' && classifications.map(cls => (
              <tr key={cls.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-6">
                  <p className="font-black text-slate-900 leading-none mb-1">{cls.name}</p>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{cls.code}</p>
                </td>
                <td className="px-8 py-6">
                  <div className="flex items-center gap-2">
                    <DollarSign className="w-3.5 h-3.5 text-slate-300" />
                    <span className="text-sm font-bold text-slate-600">{getAccountName(cls.accountId)}</span>
                  </div>
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => handleOpenForm(cls)} className="p-2 text-slate-400 hover:text-blue-600"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => handleDelete(cls.id, 'classification')} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
            {activeSubTab === 'asset-types' && assetTypes.map(type => (
              <tr key={type.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-6">
                  <p className="font-black text-slate-900 leading-none">{type.name}</p>
                </td>
                <td className="px-8 py-6">
                  <div className="flex items-center gap-2">
                    <Book className="w-3.5 h-3.5 text-slate-300" />
                    <span className="text-sm font-bold text-slate-600">{getClassificationName(type.classificationId || '')}</span>
                  </div>
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => handleOpenForm(type)} className="p-2 text-slate-400 hover:text-blue-600"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => handleDelete(type.id, 'asset-type')} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
            {((activeSubTab === 'accounts' && accounts.length === 0) || 
               (activeSubTab === 'classifications' && classifications.length === 0) || 
               (activeSubTab === 'asset-types' && assetTypes.length === 0)) && (
                <tr>
                  <td colSpan={3} className="py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs opacity-50">
                    Nenhum registro encontrado nesta categoria.
                  </td>
                </tr>
            )}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 bg-slate-900 text-white flex items-center justify-between">
              <h3 className="text-xl font-black uppercase tracking-tight">
                {editingItem ? 'Editar' : 'Cadastrar'} {activeSubTab === 'accounts' ? 'Conta' : activeSubTab === 'classifications' ? 'Classificação' : 'Tipo'}
              </h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 space-y-6">
              {activeSubTab === 'accounts' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código da Conta</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: 1.01.01.001" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome da Conta</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Notebooks e Desktop" />
                  </div>
                </>
              )}

              {activeSubTab === 'classifications' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: CLS-001" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome da Classificação</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Equipamentos de TI" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Conta Contábil Vinculada</label>
                    <select className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.accountId} onChange={e => setFormData({...formData, accountId: e.target.value})} required>
                      <option value="">Selecione uma conta...</option>
                      {accounts.map(a => <option key={a.id} value={a.id}>{a.code} - {a.name}</option>)}
                    </select>
                  </div>
                </>
              )}

              {activeSubTab === 'asset-types' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Tipo</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: MacBook" />
                  </div>
                  <div className="space-y-1.5">
